DROP PROCEDURE IF EXISTS sp_select_table $$
CREATE PROCEDURE sp_select_table(IN p_table VARCHAR(64))
BEGIN
    IF FIND_IN_SET(p_table, 'Addresses,People,Roles,Clubs,Membership,Events,PhysicalEvents,VirtualEvents') = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported table in sp_select_table';
    END IF;

    SET @sql = CONCAT('SELECT * FROM `', REPLACE(p_table, '`', '``'), '`');
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END $$

DROP PROCEDURE IF EXISTS sp_insert_row $$
CREATE PROCEDURE sp_insert_row(IN p_table VARCHAR(64), IN p_data JSON)
BEGIN
    DECLARE v_columns_valid INT DEFAULT 0;

    IF FIND_IN_SET(p_table, 'Addresses,People,Roles,Clubs,Membership,Events,PhysicalEvents,VirtualEvents') = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported table in sp_insert_row';
    END IF;

    IF JSON_LENGTH(JSON_KEYS(p_data)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Insert payload must contain at least one column';
    END IF;

    SELECT COUNT(*) INTO v_columns_valid
    FROM JSON_TABLE(JSON_KEYS(p_data), '$[*]' COLUMNS (col VARCHAR(128) PATH '$')) payload_cols
    JOIN INFORMATION_SCHEMA.COLUMNS metadata
      ON metadata.TABLE_SCHEMA = DATABASE()
     AND metadata.TABLE_NAME = p_table
     AND metadata.COLUMN_NAME = payload_cols.col;

    IF v_columns_valid <> JSON_LENGTH(JSON_KEYS(p_data)) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Insert payload contains invalid columns';
    END IF;

    SELECT
        GROUP_CONCAT(CONCAT('`', REPLACE(payload_cols.col, '`', '``'), '`') ORDER BY payload_cols.ord SEPARATOR ', '),
        GROUP_CONCAT(
            CASE
                WHEN JSON_TYPE(JSON_EXTRACT(p_data, CONCAT('$.', payload_cols.col))) = 'NULL' THEN 'NULL'
                ELSE QUOTE(JSON_UNQUOTE(JSON_EXTRACT(p_data, CONCAT('$.', payload_cols.col))))
            END
            ORDER BY payload_cols.ord SEPARATOR ', '
        )
    INTO @insert_columns, @insert_values
    FROM JSON_TABLE(JSON_KEYS(p_data), '$[*]' COLUMNS (ord FOR ORDINALITY, col VARCHAR(128) PATH '$')) payload_cols;

    SET @sql = CONCAT(
        'INSERT INTO `', REPLACE(p_table, '`', '``'), '` (', @insert_columns, ') VALUES (', @insert_values, ')'
    );

    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END $$

DROP PROCEDURE IF EXISTS sp_update_row $$
CREATE PROCEDURE sp_update_row(IN p_table VARCHAR(64), IN p_data JSON, IN p_where JSON)
BEGIN
    DECLARE v_data_columns_valid INT DEFAULT 0;
    DECLARE v_where_columns_valid INT DEFAULT 0;

    IF FIND_IN_SET(p_table, 'Addresses,People,Roles,Clubs,Membership,Events,PhysicalEvents,VirtualEvents') = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported table in sp_update_row';
    END IF;

    IF JSON_LENGTH(JSON_KEYS(p_data)) = 0 OR JSON_LENGTH(JSON_KEYS(p_where)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Update payload requires both data and where clauses';
    END IF;

    SELECT COUNT(*) INTO v_data_columns_valid
    FROM JSON_TABLE(JSON_KEYS(p_data), '$[*]' COLUMNS (col VARCHAR(128) PATH '$')) payload_cols
    JOIN INFORMATION_SCHEMA.COLUMNS metadata
      ON metadata.TABLE_SCHEMA = DATABASE()
     AND metadata.TABLE_NAME = p_table
     AND metadata.COLUMN_NAME = payload_cols.col;

    SELECT COUNT(*) INTO v_where_columns_valid
    FROM JSON_TABLE(JSON_KEYS(p_where), '$[*]' COLUMNS (col VARCHAR(128) PATH '$')) where_cols
    JOIN INFORMATION_SCHEMA.COLUMNS metadata
      ON metadata.TABLE_SCHEMA = DATABASE()
     AND metadata.TABLE_NAME = p_table
     AND metadata.COLUMN_NAME = where_cols.col;

    IF v_data_columns_valid <> JSON_LENGTH(JSON_KEYS(p_data)) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Update data contains invalid columns';
    END IF;

    IF v_where_columns_valid <> JSON_LENGTH(JSON_KEYS(p_where)) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Update where contains invalid columns';
    END IF;

    SELECT GROUP_CONCAT(
        CONCAT(
            '`', REPLACE(payload_cols.col, '`', '``'), '` = ',
            CASE
                WHEN JSON_TYPE(JSON_EXTRACT(p_data, CONCAT('$.', payload_cols.col))) = 'NULL' THEN 'NULL'
                ELSE QUOTE(JSON_UNQUOTE(JSON_EXTRACT(p_data, CONCAT('$.', payload_cols.col))))
            END
        )
        ORDER BY payload_cols.ord SEPARATOR ', '
    )
    INTO @update_set_clause
    FROM JSON_TABLE(JSON_KEYS(p_data), '$[*]' COLUMNS (ord FOR ORDINALITY, col VARCHAR(128) PATH '$')) payload_cols;

    SELECT GROUP_CONCAT(
        CONCAT(
            '`', REPLACE(where_cols.col, '`', '``'), '` = ',
            CASE
                WHEN JSON_TYPE(JSON_EXTRACT(p_where, CONCAT('$.', where_cols.col))) = 'NULL' THEN 'NULL'
                ELSE QUOTE(JSON_UNQUOTE(JSON_EXTRACT(p_where, CONCAT('$.', where_cols.col))))
            END
        )
        ORDER BY where_cols.ord SEPARATOR ' AND '
    )
    INTO @update_where_clause
    FROM JSON_TABLE(JSON_KEYS(p_where), '$[*]' COLUMNS (ord FOR ORDINALITY, col VARCHAR(128) PATH '$')) where_cols;

    SET @sql = CONCAT(
        'UPDATE `', REPLACE(p_table, '`', '``'), '` SET ', @update_set_clause, ' WHERE ', @update_where_clause
    );

    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END $$

DROP PROCEDURE IF EXISTS sp_delete_row $$
CREATE PROCEDURE sp_delete_row(IN p_table VARCHAR(64), IN p_where JSON)
BEGIN
    DECLARE v_where_columns_valid INT DEFAULT 0;

    IF FIND_IN_SET(p_table, 'Addresses,People,Roles,Clubs,Membership,Events,PhysicalEvents,VirtualEvents') = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported table in sp_delete_row';
    END IF;

    IF JSON_LENGTH(JSON_KEYS(p_where)) = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Delete where clause cannot be empty';
    END IF;

    SELECT COUNT(*) INTO v_where_columns_valid
    FROM JSON_TABLE(JSON_KEYS(p_where), '$[*]' COLUMNS (col VARCHAR(128) PATH '$')) where_cols
    JOIN INFORMATION_SCHEMA.COLUMNS metadata
      ON metadata.TABLE_SCHEMA = DATABASE()
     AND metadata.TABLE_NAME = p_table
     AND metadata.COLUMN_NAME = where_cols.col;

    IF v_where_columns_valid <> JSON_LENGTH(JSON_KEYS(p_where)) THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Delete where contains invalid columns';
    END IF;

    SELECT GROUP_CONCAT(
        CONCAT(
            '`', REPLACE(where_cols.col, '`', '``'), '` = ',
            CASE
                WHEN JSON_TYPE(JSON_EXTRACT(p_where, CONCAT('$.', where_cols.col))) = 'NULL' THEN 'NULL'
                ELSE QUOTE(JSON_UNQUOTE(JSON_EXTRACT(p_where, CONCAT('$.', where_cols.col))))
            END
        )
        ORDER BY where_cols.ord SEPARATOR ' AND '
    )
    INTO @delete_where_clause
    FROM JSON_TABLE(JSON_KEYS(p_where), '$[*]' COLUMNS (ord FOR ORDINALITY, col VARCHAR(128) PATH '$')) where_cols;

    SET @sql = CONCAT(
        'DELETE FROM `', REPLACE(p_table, '`', '``'), '` WHERE ', @delete_where_clause
    );

    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END $$

DELIMITER ;